def get_drive_service():
    """Connects to Google Drive using service account."""
    try:
        # Try Streamlit secrets first (for Streamlit Cloud deployment)
        sa_info = st.secrets["gcp_service_account"]
    except Exception:
        # Fallback: load from local file
        import os
        sa_path = os.path.join(os.path.dirname(__file__), "service_account.json")
        if os.path.exists(sa_path):
            with open(sa_path) as f:
                sa_info = json.load(f)
        else:
            return None
    creds = service_account.Credentials.from_service_account_info(
        sa_info if isinstance(sa_info, dict) else dict(sa_info),
        scopes=["https://www.googleapis.com/auth/drive.readonly"]
    )
    return build("drive", "v3", credentials=creds)

@st.cache_data(ttl=300)
def listar_archivos(folder_id, extension=None):
    """Lista archivos de una carpeta de Drive."""
    service = get_drive_service()
    if not service: return []
    q = f"\"{folder_id}\" in parents and trashed=false"
    if extension:
        if extension == "csv":
            q += " and mimeType=\"text/csv\""
        elif extension == "xlsx":
            q += " and (mimeType=\"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\" or mimeType=\"application/vnd.ms-excel\")"
    results = service.files().list(q=q, fields="files(id,name,modifiedTime)", orderBy="name").execute()
    return results.get("files", [])

@st.cache_data(ttl=300)
def descargar_csv(file_id, file_name):
    """Descarga un CSV de Drive y lo devuelve como DataFrame."""
    service = get_drive_service()
    if not service: return pd.DataFrame()
    request = service.files().get_media(fileId=file_id)
    buf = io.BytesIO()
    downloader = MediaIoBaseDownload(buf, request)
    done = False
    while not done:
        _, done = downloader.next_chunk()
    buf.seek(0)
    return pd.read_csv(buf)

@st.cache_data(ttl=300)
def descargar_excel(file_id, file_name, sheet_name=0, header=0, skiprows=None):
    """Descarga un Excel de Drive y lo devuelve como DataFrame."""
    service = get_drive_service()
    if not service: return pd.DataFrame()
    request = service.files().get_media(fileId=file_id)
    buf = io.BytesIO()
    downloader = MediaIoBaseDownload(buf, request)
    done = False
    while not done:
        _, done = downloader.next_chunk()
    buf.seek(0)
    return pd.read_excel(buf, sheet_name=sheet_name, header=header, skiprows=skiprows)

def fnum(v, dec=0):
    """Formato argentino: punto miles, coma decimal."""
    if pd.isna(v): return "-"
    if dec == 0:
        s = f"{v:,.0f}"
    else:
        s = f"{v:,.{dec}f}"
    return s.replace(",","X").replace(".",",").replace("X",".")

