@st.cache_data(ttl=300)
def cargar_seguimiento_drive():
    """Carga todos los CSVs de seguimiento desde Drive."""
    archivos = listar_archivos(FOLDER_SEGUIMIENTO, "csv")
    if not archivos:
        return pd.DataFrame(), []
    frames = []
    nombres = []
    for f in archivos:
        df = descargar_csv(f["id"], f["name"])
        if not df.empty:
            frames.append(df)
            nombres.append(f["name"])
    if not frames: return pd.DataFrame(), []
    df = pd.concat(frames, ignore_index=True)
    df["fecha"] = pd.to_datetime(df["fecha"])
    df["sector"] = df["sector"].fillna("-").astype(str).replace("nan", "-")
    if "mes" not in df.columns:
        df["mes"] = df["fecha"].dt.month
    df = df.drop_duplicates(subset=["id_potrero","fecha","sensor"]).sort_values(["campo","potrero","fecha"])
    return df, nombres

@st.cache_data(ttl=300)
def cargar_config_drive():
    """Carga clasificacion y EUR desde Drive.
    RFA ya no viene del config: se lee del ERA5 diario."""
    archivos = listar_archivos(FOLDER_CONFIG, "xlsx")
    df_clasif = pd.DataFrame()
    df_eur    = pd.DataFrame()
    nombres   = []
    for f in archivos:
        nombre = f["name"].lower()
        nombres.append(f["name"])
        if any(p in nombre for p in ["clasificacion","clasif","areas","potreros"]):
            df_raw = descargar_excel(f["id"], f["name"])
            df_raw = df_raw.drop(columns=[c for c in df_raw.columns if "Unnamed" in str(c)], errors="ignore")
            # sup_efec y sup_util ya vienen calculados desde el script GEE
            df_clasif = df_raw
        elif "eur" in nombre or "rfa" in nombre:
            # Hoja2: _1 | _2 | mes | campo | EUR | RFA(ignorada)
            df_raw = descargar_excel(f["id"], f["name"], sheet_name="Hoja2", header=None, skiprows=2)
            df_raw.columns = ["_1","_2","mes","campo","EUR","_rfa"]
            df_raw = df_raw[["mes","campo","EUR"]].dropna(subset=["campo"])
            df_raw = df_raw[df_raw["campo"] != "campo"].copy()
            for c in ["mes","EUR"]: df_raw[c] = pd.to_numeric(df_raw[c], errors="coerce")
            df_raw = df_raw.dropna(subset=["mes"])
            df_raw["mes"] = df_raw["mes"].astype(int)
            df_eur = df_raw
    return df_clasif, df_eur, nombres

