@st.cache_data(ttl=300)
def cargar_consumo_drive():
    """Carga el Excel de consumo desde Drive.
    Formato esperado: hoja 'Export', fila 1 = cabecera Año-Mes, fila 2 = 'Lote'/'Consumo',
    filas siguientes = datos por potrero (raciones).
    """
    archivos = listar_archivos(FOLDER_CONSUMO, "xlsx")
    if not archivos:
        return pd.DataFrame()
    frames = []
    for f in archivos:
        try:
            df_raw = descargar_excel(f["id"], f["name"], sheet_name="Export", header=None)
            # Fila 0: ["Año-Mes", "2025-01", ...] — cabecera de meses
            # Fila 1: ["Lote", "Consumo", ...] — subencabezado
            # Filas 2+: datos
            cabecera = df_raw.iloc[0].tolist()   # Año-Mes, 2025-01, ...
            datos = df_raw.iloc[2:].copy()
            datos.columns = cabecera
            datos = datos.rename(columns={"Año-Mes": "lote"})
            # Eliminar última fila (línea de filtros)
            datos = datos[~datos["lote"].astype(str).str.startswith("Filtros")]
            datos = datos.dropna(subset=["lote"])
            datos = datos[datos["lote"].astype(str).str.strip() != ""]
            # Pivot a formato largo
            meses_cols = [c for c in datos.columns if c not in ("lote", "Total")]
            df_long = datos.melt(id_vars="lote", value_vars=meses_cols, var_name="anio_mes", value_name="raciones")
            df_long["raciones"] = pd.to_numeric(df_long["raciones"], errors="coerce").fillna(0)
            df_long["fecha"] = pd.to_datetime(df_long["anio_mes"] + "-01", errors="coerce")
            df_long = df_long.dropna(subset=["fecha"])
            df_long["mes"] = df_long["fecha"].dt.month
            df_long["anio"] = df_long["fecha"].dt.year
            df_long["mes_lbl"] = df_long["mes"].map(MESES_CORTOS)
            df_long["kgMS"] = df_long["raciones"] * KGMS_POR_RACION
            df_long["campania"] = df_long.apply(
                lambda r: f"{int(r['anio'])}/{int(r['anio'])+1}" if r["mes"] >= 7 else f"{int(r['anio'])-1}/{int(r['anio'])}", axis=1)
            df_long["lote"] = df_long["lote"].astype(str).str.strip()
            frames.append(df_long)
        except Exception:
            pass
    if not frames:
        return pd.DataFrame()
    return pd.concat(frames, ignore_index=True)

# === FUNCIONES DE CÁLCULO ===

UMBRALES_ALLSKY = {
    1: 8.47, 2: 7.30, 3: 6.00, 4: 4.69, 5: 3.74,
    6: 3.67, 7: 4.20, 8: 5.54, 9: 6.68, 10: 7.44, 11: 8.24, 12: 8.47
}

@st.cache_data(ttl=300)
def calcular_ppna(df_seg, df_eur, df_era5):
    """TC_d = EVI × RFA_ERA5_d × EUR_mes × 10
    RFA se une por fecha exacta desde el ERA5 diario (BUSCARV).
    """
    # Filtrar EVI fuera de rango válido
    df = df_seg[(df_seg["EVI_promedio"] >= 0.11) & (df_seg["EVI_promedio"] <= 0.95)].copy()
    # Sacar campaña 2018/2019
    df = df[df["campania"] != "2018/2019"]
    # Traer RFA del ERA5 diario por fecha exacta
    rfa_diario = df_era5[["fecha","RFA_MJ_m2_dia"]].drop_duplicates("fecha")
    df = df.merge(rfa_diario, on="fecha", how="left")
    # Traer EUR por mes
    df = df.merge(df_eur[["campo","mes","EUR"]], on=["campo","mes"], how="left")
    df["PPNA_kgMS_ha_d"] = df["EVI_promedio"] * df["RFA_MJ_m2_dia"] * df["EUR"] * 10
    # Descartar filas sin PPNA (falta RFA o EUR) para que no contaminen
    # la integración trapezoidal con NaN
    df = df.dropna(subset=["PPNA_kgMS_ha_d"])
    return df

def mes_orden(mes): return ORDEN_MESES.index(mes)+1 if mes in ORDEN_MESES else 0

def calcular_dias_activos(df_era5):
    """Días por mes donde RFA ERA5 >= umbral ALLSKY -1σ."""
    df = df_era5.copy()
    df["umbral"] = df["mes"].map(UMBRALES_ALLSKY)
    df["activo"] = (df["RFA_MJ_m2_dia"] >= df["umbral"]).astype(int)
    dias = df.groupby(["anio","mes"]).agg(
        dias_activos=("activo","sum")
    ).reset_index()
    return dias

@st.cache_data(ttl=300)
def calcular_mensual(df_ppna, df_era5):
    """PPNA_m por potrero usando integración trapezoidal.
    TC_d = EVI × RFA_ERA5_d × EUR × 10 (RFA real del día de imagen).
    Extremos del mes extendidos al primer y último día.
    """
    fecha_max_global = df_ppna["fecha"].max()
    mes_max = fecha_max_global.month
    anio_max = fecha_max_global.year

    registros = []
    grupos = df_ppna.groupby(["campo","sector","potrero","mes","campania"])

    for keys, grp in grupos:
        campo, sector, potrero, mes, campania = keys
        id_potrero = grp["id_potrero"].iloc[0] if "id_potrero" in grp.columns else potrero
        grp = grp.sort_values("fecha").drop_duplicates("fecha")
        anio = int(grp["fecha"].dt.year.iloc[0])

        # Extremos del mes
        d_inicio = pd.Timestamp(anio, mes, 1)
        if mes == mes_max and anio == anio_max:
            d_fin = fecha_max_global
        else:
            d_fin = pd.Timestamp(anio, mes, calendar.monthrange(anio, mes)[1])

        fechas = list(grp["fecha"])
        vals   = list(grp["PPNA_kgMS_ha_d"])

        all_f = [d_inicio] + fechas + [d_fin]
        all_v = [vals[0]]  + vals   + [vals[-1]]

        seen = set(); f_c = []; v_c = []
        for f, v in zip(all_f, all_v):
            if f not in seen:
                seen.add(f); f_c.append(f); v_c.append(v)

        PPNA_m = sum((v_c[i]+v_c[i+1])/2*(f_c[i+1]-f_c[i]).days
                     for i in range(len(f_c)-1))

        TC_d_mean = grp["PPNA_kgMS_ha_d"].mean()

        registros.append({
            "campo": campo, "sector": sector, "potrero": potrero, "id_potrero": id_potrero,
            "mes": mes, "campania": campania,
            "PPNA_d": TC_d_mean, "n_obs": len(grp),
            "f_min": grp["fecha"].min(), "f_max": grp["fecha"].max(),
            "PPNA_m": PPNA_m
        })

    m = pd.DataFrame(registros)
    m["f_min"] = pd.to_datetime(m["f_min"])
    m["f_max"] = pd.to_datetime(m["f_max"])
    m["orden"] = m["mes"].apply(mes_orden)
    return m

@st.cache_data(ttl=300)
def calcular_acumulada(mensual, df_clasif):
    pot = mensual.groupby(["campo","campania","id_potrero"])[["PPNA_m"]].sum().reset_index()
    pot.columns = ["campo","campania","id_potrero","PPNA_acum"]
    pot_sup = pot.merge(df_clasif[["campo","id_potrero","sup_util"]], on=["campo","id_potrero"], how="left")
    pot_sup["peso"] = pot_sup["PPNA_acum"] * pot_sup["sup_util"]
    campo_acum = pot_sup.groupby(["campo","campania"]).apply(
        lambda x: x["peso"].sum() / x["sup_util"].sum() if x["sup_util"].sum() > 0 else 0
    ).reset_index()
    campo_acum.columns = ["campo","campania","PPNA_acumulada"]
    return campo_acum, pot

@st.cache_data(ttl=300)
def tc_campo_fn(df_ppna):
    uf = df_ppna["fecha"].max(); um = uf.month; ua = uf.year
    act = df_ppna[(df_ppna["fecha"].dt.month==um)&(df_ppna["fecha"].dt.year==ua)].groupby("campo")["PPNA_kgMS_ha_d"].mean()
    hist = df_ppna[df_ppna["fecha"].dt.month==um].groupby("campo")["PPNA_kgMS_ha_d"].mean()
    r = pd.DataFrame({"TC_act":act,"TC_hist":hist})
    r["var"] = (r["TC_act"]-r["TC_hist"])/r["TC_hist"]
    return r, um, ua, uf

def color_var(v):
    if pd.isna(v): return "#9E9E9E","Sin dato"
    if v < -0.10: return "#B71C1C","Muy por debajo"
    if v < 0.00: return "#F57C00","Debajo"
    if v < 0.15: return "#FBC02D","Normal"
    return "#2E7D32","Por encima"

def color_pot(val, prom, sigma):
    if pd.isna(val) or sigma==0: return "#E0E0E0"
    d = val-prom
    if d<=-1.5*sigma: return "#B71C1C"
    if d<-0.5*sigma: return "#EF5350"
    if abs(d)<=0.5*sigma: return "#E0E0E0"
    if d<1.5*sigma: return "#66BB6A"
    return "#1B5E20"

