with tab5:
    btn_actualizar()
    @st.fragment
    def _tab5_render():
        st.markdown('<div class="section-title">PRODUCTIVIDAD HISTÓRICA</div>', unsafe_allow_html=True)
        st.caption("Estadísticas por potrero y campo calculadas sobre todas las campañas disponibles.")

        # Selector de campo
        _ch_idx = campos.index(st.session_state.get("campo_hist", campos[0])) if st.session_state.get("campo_hist") in campos else 0
        campo_h = st.selectbox("Campo:", campos, index=_ch_idx,
                               format_func=lambda x: NOMBRE_CAMPOS.get(x,x), key="campo_hist")
        mensual_h = mensual[mensual["campo"]==campo_h].copy()

        # --- Construir tabla histórica mensual por potrero ---
        # Tasa de crecimiento diaria promedio por potrero/mes sobre todas las campañas
        hist_pot = mensual_h.groupby(["potrero","mes","orden"]).agg(
            TC_prom=("PPNA_d","mean"),
            TC_std=("PPNA_d","std"),
            PPNA_m_prom=("PPNA_m","mean"),
            PPNA_m_std=("PPNA_m","std"),
            n_camp=("campania","nunique")
        ).reset_index().sort_values("orden")
        hist_pot["TC_std"] = hist_pot["TC_std"].fillna(0)
        hist_pot["PPNA_m_std"] = hist_pot["PPNA_m_std"].fillna(0)
        hist_pot["ml"] = hist_pot["mes"].map(MESES_CORTOS)

        # Productividad acumulada histórica por potrero (por campaña, luego promedio)
        acum_hist = mensual_h.groupby(["potrero","campania"])["PPNA_m"].sum().reset_index()
        acum_hist_stats = acum_hist.groupby("potrero")["PPNA_m"].agg(
            prom="mean", std="std", n="count"
        ).reset_index().fillna(0)
        acum_hist_stats.columns = ["potrero","Acum_prom","Acum_std","n_camp"]

        # --- Productividad histórica del CAMPO (promedio de todos los potreros) ---
        hist_campo = mensual_h.groupby(["mes","orden","campania"]).agg(
            TC_campo=("PPNA_d","mean"),
            PPNA_m_campo=("PPNA_m","mean")
        ).reset_index()
        hist_campo_stats = hist_campo.groupby(["mes","orden"]).agg(
            TC_prom=("TC_campo","mean"),
            TC_std=("TC_campo","std"),
            PPNA_m_prom=("PPNA_m_campo","mean"),
            PPNA_m_std=("PPNA_m_campo","std"),
            n_camp=("campania","nunique")
        ).reset_index().sort_values("orden").fillna(0)
        hist_campo_stats["ml"] = hist_campo_stats["mes"].map(MESES_CORTOS)

        # KPIs resumen del campo
        acum_campo_hist = mensual.groupby("campania")["PPNA_m"].mean().reset_index()
        campo_acum_prom = acum_campo_hist["PPNA_m"].sum() / acum_campo_hist["campania"].nunique() if not acum_campo_hist.empty else 0
        # Por campaña: suma de todos los meses promediados por potrero
        acum_por_camp = mensual_h.groupby("campania").apply(lambda x: x.groupby("potrero")["PPNA_m"].sum().mean()).reset_index()
        acum_por_camp.columns = ["campania","acum_campo"]
        campo_acum_prom = acum_por_camp["acum_campo"].mean()
        campo_acum_std = acum_por_camp["acum_campo"].std()
        campo_n_camp = acum_por_camp["campania"].nunique()

        st.markdown("---")
        st.markdown("#### 📌 Resumen del Campo")
        ck1, ck2, ck3 = st.columns(3)
        with ck1:
            st.metric("PPNA Acumulada Media del Campo", f"{fnum(campo_acum_prom)} kgMS/ha")
        with ck2:
            st.metric("Desvío entre Campañas", f"± {fnum(campo_acum_std)} kgMS/ha")
        with ck3:
            st.metric("Campañas analizadas", str(campo_n_camp))

        # ---- SECCIÓN 1: Productividad histórica del campo ----
        st.markdown("---")
        st.markdown("#### Productividad Histórica del Campo")

        st.markdown("**Tasa de Crecimiento Diaria — Promedio ± Desvío (kgMS/ha·día)**")
        fig_tc = go.Figure()
        fig_tc.add_trace(go.Bar(
            x=hist_campo_stats["ml"], y=hist_campo_stats["TC_prom"],
            name="TC promedio", marker_color="#2E7D32",
            error_y=dict(type="data", array=hist_campo_stats["TC_std"].tolist(), visible=True, color="#1B5E20"),
            hovertemplate="<b>%{x}</b><br>TC: %{y:.2f} ± <extra></extra>"
        ))
        fig_tc.update_layout(
            height=380, template="plotly_white", separators=",.",
            xaxis=dict(categoryorder="array", categoryarray=[MESES_CORTOS[m] for m in ORDEN_MESES]),
            yaxis_title="kgMS/ha·día", showlegend=False,
            margin=dict(t=10,b=10)
        )
        st.plotly_chart(fig_tc, use_container_width=True)

        # Tabla resumen campo
        tabla_campo = hist_campo_stats[["ml","TC_prom","TC_std","PPNA_m_prom","PPNA_m_std","n_camp"]].copy()
        tabla_campo.columns = ["Mes","TC Prom (kg/ha·d)","TC Desvío","PPNA Mens. (kg/ha)","PPNA Desvío","N Campañas"]
        st.dataframe(
            tabla_campo.style.format({
                "TC Prom (kg/ha·d)": lambda x: fnum(x,2),
                "TC Desvío": lambda x: fnum(x,2),
                "PPNA Mens. (kg/ha)": lambda x: fnum(x,0),
                "PPNA Desvío": lambda x: fnum(x,0),
            }).background_gradient(subset=["TC Prom (kg/ha·d)"], cmap="YlGn"),
            use_container_width=True, hide_index=True
        )

        # ---- SECCIÓN 2: Productividad histórica por potrero ----
        st.markdown("---")
        st.markdown("#### 🗂️ Productividad Histórica por Potrero")

        potreros_disp = sorted(hist_pot["potrero"].unique())
        _ph_idx = potreros_disp.index(st.session_state["pot_hist"]) if st.session_state["pot_hist"] in potreros_disp else 0
        pot_sel = st.selectbox("Seleccioná un potrero:", potreros_disp, index=_ph_idx, key="pot_hist")

        dp_hist = hist_pot[hist_pot["potrero"]==pot_sel].copy()
        acum_pot_data = acum_hist_stats[acum_hist_stats["potrero"]==pot_sel]
        acum_prom = acum_pot_data["Acum_prom"].values[0] if not acum_pot_data.empty else 0
        acum_std = acum_pot_data["Acum_std"].values[0] if not acum_pot_data.empty else 0
        n_c = int(acum_pot_data["n_camp"].values[0]) if not acum_pot_data.empty else 0

        # KPIs del potrero
        k1,k2,k3 = st.columns(3)
        with k1:
            st.metric("PPNA Acumulada Promedio", f"{fnum(acum_prom)} kgMS/ha")
        with k2:
            st.metric("Desvío entre Campañas", f"± {fnum(acum_std)} kgMS/ha")
        with k3:
            st.metric("Campañas analizadas", str(n_c))

        col_p1, col_p2 = st.columns(2)
        with col_p1:
            st.markdown(f"**TC Diaria mensual — {pot_sel}**")
            fig_p1 = go.Figure()
            fig_p1.add_trace(go.Bar(
                x=dp_hist["ml"], y=dp_hist["TC_prom"],
                marker_color="#1976D2",
                error_y=dict(type="data", array=dp_hist["TC_std"].tolist(), visible=True, color="#0D47A1"),
                hovertemplate="<b>%{x}</b><br>TC: %{y:.2f} kgMS/ha·d<extra></extra>"
            ))
            fig_p1.update_layout(
                height=320, template="plotly_white", separators=",.",
                xaxis=dict(categoryorder="array", categoryarray=[MESES_CORTOS[m] for m in ORDEN_MESES]),
                yaxis_title="kgMS/ha·día", margin=dict(t=10,b=10), showlegend=False
            )
            st.plotly_chart(fig_p1, use_container_width=True)

        # Tabla detalle potrero
        tabla_pot = dp_hist[["ml","TC_prom","TC_std","PPNA_m_prom","PPNA_m_std","n_camp"]].copy()
        tabla_pot.columns = ["Mes","TC Prom (kg/ha·d)","TC Desvío","PPNA Mens. (kg/ha)","PPNA Desvío","N Campañas"]
        st.dataframe(
            tabla_pot.style.format({
                "TC Prom (kg/ha·d)": lambda x: fnum(x,2),
                "TC Desvío": lambda x: fnum(x,2),
                "PPNA Mens. (kg/ha)": lambda x: fnum(x,0),
                "PPNA Desvío": lambda x: fnum(x,0),
            }).background_gradient(subset=["TC Prom (kg/ha·d)"], cmap="Blues"),
            use_container_width=True, hide_index=True
        )

    _tab5_render()

